/**
 * Update Request Code for Volkov Labs Business Forms:
 * This code is executed when the form's submit button is clicked.
 * Sends specific data to an API endpoint.
 */

// Wrap in 'async' to enable await functionality
(async () => {
  // --- Debugging (Optional - remove in production) ---
  // console.log("Context object:", context);
  // console.log("Context elements:", context.elements);
  // --- End Debugging ---

  // 'context.elements' is an array of all configured form elements.
  const elements = context.panel.elements;
  console.log("Raw context.elements object:", elements); // debugging
  const elementsToInclude = Array.isArray(elements) ? elements : [];

  // Construct the payload; key-value pairs of form element IDs and their values.
  const payload = {};

  if (elementsToInclude.length > 0) {
    elementsToInclude.forEach((element) => {
      console.log(
        `Processing element: ID='${element.id}', Value='${element.value}', Type='${element.type}'`
      ); // debugging

      payload[element.id] = element.value;
    });
  } else {
    // Log a warning if no elements are found.
    console.warn("No form elements found to send to API.");
  }

  payload.timestamp = Date.now();
  console.log("Payload being sent:", payload); // debugging

  // Define the API endpoint where the data will be sent.
  const apiEndpoint = "http://localhost:8080/p_vs_t_scan";

  // Define HTTP request options for the fetch call.
  const requestOptions = {
    method: "POST", // TODO: Determine if POST or PUT is more appropriate.
    headers: {
      "Content-Type": "application/json",
    },
    // Convert the JavaScript payload object into JSON for the request body.
    body: JSON.stringify(payload),
  };

  // Helper function to display notifications
  const showNotification = (type, message) => {
    if (context.panel && typeof context.panel[type] === "function") {
      context.panel[type](message);
    } else {
      // Fallback to console if the notification function is not available
      console[type === "error" ? "error" : "log"]("Notification:", message);
    }
  };

  // Make the HTTP request using the Fetch API.
  try {
    const response = await fetch(apiEndpoint, requestOptions);

    if (!response.ok) {
      const errorData = await response
        .json()
        .catch(() => ({
          message:
            "Unknown API error, non-JSON response or empty body.",
        }));

      showNotification(
        "error",
        "API Error: " + (errorData.message || response.statusText)
      );
      console.error("API Error:", response.status, errorData);
      return;
    }

    const result = await response.json();

    showNotification("success", "Data published successfully!");
    console.log("API Response:", result);

    // Optional: TODO: call initial request to update form values?
  } catch (error) {
    // Catch network errors (e.g., endpoint unreachable, CORS).
    showNotification("error", "Network Error: " + error.message);
    console.error("Network Error:", error);
  }
})();

