(async () => {
  const elements = context.panel.elements;
  const mr = elements.find((e) => e.id === 'MR');
  if (!mr) {
    console.error('MR element not found');
    return;
  }

  const payload = { MR: mr.value };
  console.log('Payload being sent:', payload);

  const apiEndpoint = 'http://localhost:8080/single_mass_scan';

  const showNotification = (type, message) => {
    if (context.panel && typeof context.panel[type] === 'function') {
      context.panel[type](message);
    } else {
      console[type === 'error' ? 'error' : 'log']('Notification:', message);
    }
  };

  try {
    const response = await fetch(apiEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({ message: 'Unknown error' }));
      showNotification('error', 'API Error: ' + (errorData.message || response.statusText));
      console.error('API Error:', response.status, errorData);
      return;
    }

    const result = await response.json();
    showNotification('success', 'Measurement started!');
    console.log('API Response:', result);
  } catch (error) {
    showNotification('error', 'Network Error: ' + error.message);
    console.error('Network Error:', error);
  }
})();
